import React from 'react';
import './credenciales.css';

function credenciales_usuario() {
  return (
    <div className="contenedor_credenciales_usuario">
      <div className="espacios_de_credenciales">
        <input type="email" name="" id="" placeholder='Nombre' />
        <label htmlFor="Nombre">Nombre</label>
      </div>
    </div>
  );
}

export default credenciales_usuario;
